using ModelContextProtocol.Server;
using System.ComponentModel;

namespace ConfigMcpServer.Tools;

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes the input message back, optionally in uppercase.")]
    public static string Echo(
        [Description("The message to echo back")] string message,
        [Description("If true, converts the message to uppercase")] bool uppercase = false)
    {
        return uppercase ? message.ToUpperInvariant() : message;
    }

    [McpServerTool, Description("Returns the current server UTC date and time.")]
    public static string GetServerTime()
    {
        return DateTime.UtcNow.ToString("o");
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace ConfigMcpServer.Resources;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false },
            Version = "1.0.0"
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }

    [McpServerResource(
        UriTemplate = "config://app/endpoints",
        Name = "API Endpoints",
        MimeType = "application/json"),
     Description("Returns the list of available API endpoints.")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Path = "/api/users", Method = "GET", Description = "List all users" },
            new { Path = "/api/users/{id}", Method = "GET", Description = "Get user by ID" },
            new { Path = "/api/health", Method = "GET", Description = "Health check" }
        };

        return JsonSerializer.Serialize(endpoints, JsonOptions);
    }
}

